import xml.etree.ElementTree as ET
from collections import Counter
import boto3
from botocore import UNSIGNED
from botocore.config import Config

source = "datagov/postsecondary-school-locations-current-40ae1/files/nces::postsecondary-school-locations-current-1.txt"
bucket = "lakeqa-yc4103-datalake"
obj = boto3.client("s3", config=Config(signature_version=UNSIGNED)).get_object(Bucket=bucket, Key=source)
root = ET.fromstring(obj["Body"].read())
ns = {"k": "http://www.opengis.net/kml/2.2"}

rows = []
for placemark in root.findall(".//k:Placemark", ns):
    row = {}
    for simple_data in placemark.findall('.//k:SimpleData', ns):
        row[simple_data.attrib.get("name")] = simple_data.text
    if row.get("STFIP") == "25":
        rows.append(row)

county_counts = Counter(row["NMCNTY"] for row in rows)
candidates = {"Middlesex County", "Worcester County"}
candidate_counts = {county: county_counts[county] for county in candidates}
answer = max(candidate_counts.items(), key=lambda x: (x[1], x[0]))[0]
